<template>
  <div>
    <a-list item-layout="horizontal" :data-source="data">
      <a-list-item slot="renderItem" slot-scope="item">
        <a-list-item-meta description="">
          <div slot="title">
            <div class="parent-div">
              <div style="display: flex;">
                <div style="width: 48px; flex-shrink: 0;">
                  <a-icon type="check-square" style="font-size: 48px; color: brown;"/>
                </div>
                <div style="flex-grow: 1; padding-left: 20px;">
                  <h3 class="text-bolder">{{ item.name }}</h3>
                  <p style="margin-bottom: 0;">{{ item.description }}</p>
                </div>
              </div>
            </div>
          </div>
        </a-list-item-meta>
      </a-list-item>
    </a-list>
  </div>
</template>
<script>
import { getContestants } from '@/api/judge'
export default {
  data() {
    return {
      data: [],
    }
  },
  mounted() {
    this.loadData()
  },
  methods: {
    loadData() {
      getContestants(this.$route.query.voteId).then(res => {
        this.data = res
      })
    },
  },
}
</script>
<style lang="less" scoped>
@media only screen and (max-width: 767px) {
  .text-bolder {
    text-shadow: 0.3px 0 0 currentColor, -0.3px 0 0 currentColor, 0 0.3px 0 currentColor, 0 -0.3px 0 currentColor;
  }
}
</style>
